using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>();

[SimpleJob(RuntimeMoniker.Net90)]
[SimpleJob(RuntimeMoniker.Net100)]
[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Generate a realistic text corpus
        var rng = new Random(42);
        var sampleWords = new[]
        {
            "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
            "performance", "benchmarking", "optimization", "infrastructure",
            "a", "an", "it", "is", "of", "to", "in", "and", "for", "on",
            "extraordinarily", "internationalization", "characteristically"
        };
        var words = new string[10_000];
        for (int i = 0; i < words.Length; i++)
            words[i] = sampleWords[rng.Next(sampleWords.Length)];
        _analyzer = new TextAnalyzer(string.Join(' ', words));
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

